16	
17	@Observable
18	final class DoseBarViewModel {
19	    
20	    @ObservationIgnored
21	    @Injected(\.doseSampleManager) private var doseSampleManager
22	    
23	    @ObservationIgnored
24	    @Injected(\.dosePageBuilder) private var dosePageBuilder
25	    
26	    @ObservationIgnored
27	    @Injected(\.doseBarCalculator) private var doseBarCalculator
28	    
29	    @ObservationIgnored
30	    @Injected(\.excludedIntervalsManager) private var excludedIntervalsManager
31	    
32	    private(set) var pageBars: [DosePage] = []
33	    
34	    var doseRange: DoseRange
35	    var backgroundHandling: DoseSettings.BackgroundHandling?
36	    var barsAnimationID: Int = 0
37	    let reloadSubject: CurrentValueSubject<Bool, Never> = .init(false)
38	    private let dataFilter: DoseBarDataFilter
39	    
40	    @ObservationIgnored
41	    private var fillStartDate: Date?
42	    
43	    @ObservationIgnored
44	    private var cancellables: Set<AnyCancellable> = .init()
45	    
46	    init(rangeSubject: CurrentValueSubject<DoseRange, Never>, dataFilter: DoseBarDataFilter = .all) {
47	        self.doseRange = rangeSubject.value
48	        self.dataFilter = dataFilter
49	        
50	        rangeSubject
51	            .dropFirst()
52	            .sink { [weak self] range in
53	                guard let self else { return }
54	                self.doseRange = range
