65	                self.scheduleRecreate()
66	            }
67	            .store(in: &cancellables)
68	        
69	        doseSampleManager
70	            .newDoseCounterSubject
71	            .receive(on: DispatchQueue.main)
72	            .sink { [weak self] doseCounter in
73	                guard let self else { return }
74	                if pageBars.isEmpty {
75	                    if self.fillStartDate == nil {
76	                        self.fillStartDate = doseCounter.date
77	                    }
78	                    self.scheduleRecreate()
79	                } else {
80	                    Task {
81	                       await self.appendNew(doseCounter: doseCounter)
82	                    }
83	                }
84	                
85	            }
86	            .store(in: &cancellables)
87	        
88	        self.backgroundHandling = doseSampleManager.backgroundHandlingSubject?.value
89	        doseSampleManager.backgroundHandlingSubject?
90	            .dropFirst()
91	            .receive(on: DispatchQueue.main)
92	            .sink { [weak self] backgroundHandling in
93	                guard let self else { return }
94	                self.backgroundHandling = backgroundHandling
95	                Task {
96	                    await self.recalculate()
97	                }
98	            }
99	            .store(in: &cancellables)
100	        
101	        excludedIntervalsManager
102	            .changedSubject
103	            .receive(on: DispatchQueue.main)
104	            .sink { [weak self] in
105	                guard let self else { return }
106	                Task {
107	                    await self.recalculate()
108	                }
109	            }
110	            .store(in: &cancellables)
111	    }
112	    
113	    func reset() {
114	        fillStartDate = .now
115	        scheduleRecreate()
116	    }
117	    
118	    @ObservationIgnored
119	    private var recreateTask: Task<Void, Never>?
120	    
121	    private func scheduleRecreate() {
122	        recreateTask?.cancel()
123	        recreateTask = Task { [weak self] in
124	            guard let self else { return }
125	            await self.recreate()
126	        }
127	    }
128	    
129	    @MainActor
130	    private func appendNew(doseCounter: DoseCounter) async {
131	        var hasChanges = false
132	        for page in pageBars {
133	            var updatePage = false
134	            for bar in page.bars {
135	                guard bar.updateAnchorsIfNeeded(with: doseCounter) else { continue }
136	                await applyCalculation(to: bar)
137	                updatePage = true
138	            }
139	            
140	            if updatePage {
141	                page.recalculateDisplayedDose()
142	                hasChanges = true
143	            }
144	        }
145	        
146	        if hasChanges {
147	            barsAnimationID &+= 1
148	        }
149	    }
150	    
151	    private func recalculate() async {
152	        for pageIndex in pageBars.indices {
153	            let page = pageBars[pageIndex]
154	            for bar in page.bars {
155	                await applyCalculation(to: bar)
156	            }
157	            page.recalculateDisplayedDose()
158	        }
159	        barsAnimationID &+= 1
160	    }
161	    
162	    private func recreate() async {
163	        guard let firstPage = await makePage(page: 0) else { return }
164	        guard !Task.isCancelled else { return }
165	        
166	        await MainActor.run {
167	            self.pageBars = [firstPage]
168	        }
169	        self.reloadSubject.send(true)
170	    }
171	    
172	    private func makePage(page: Int) async -> DosePage? {
173	        guard let fillStartDate else { return nil }
174	        guard let page = await dosePageBuilder.makePage(
175	            range: doseRange,
176	            page: page,
177	            startDate: fillStartDate
178	        ) else { return nil }
179	        
180	        guard !Task.isCancelled else { return nil }
181	        
182	        for bar in page.bars {
183	            await applyCalculation(to: bar)
184	        }
185	        
186	        page.recalculateDisplayedDose()
187	        return page
188	    }
189	    
190	    func preloadPage(_ page: Int) async {
191	        guard !pageBars.contains(where: { $0.id == page }) else { return }
192	        guard let pageModel = await makePage(page: page) else { return }
193	        guard !Task.isCancelled else { return }
194	        
195	        await MainActor.run {
196	            self.pageBars.append(pageModel)
197	        }
198	    }
199	    
200	    private func applyCalculation(to bar: DoseBar) async {
201	        guard let backgroundHandling else { return }
202	        await doseBarCalculator.calculate(
203	            bar: bar,
204	            handling: backgroundHandling,
205	            gaps: doseSampleManager.gaps,
206	            excluded: excludedIntervalsManager.intervals
207	        )
208	    }
209	}
