18	/// Кэш сырых точек DoseCounter
19	actor DoseCounterCache {
20	    
21	    /// Use case, который умеет получать данные дозиметра из хранилища.
22	    @Injected(\.doseCounterFetchUseCase) private var fetchUseCase
23	    
24	    private var cached: [DoseCounter] = []
25	    private var covered: DateInterval? = nil
26	    private var liveStart: Date? = nil
27	    private var deviceId: String?
28	
29	    /// В каждый момент времени у нас может быть только одна полезная догрузка влево:
30	    /// от requested.start до covered.start.
31	    /// Если приходит второй такой же или более узкий запрос — просто ждём текущий.
32	    /// Если приходит более широкий — догружаем только недостающий левый хвост.
33	    private var inFlightLeftEdge: DateInterval?
34	    private var inFlightTask: Task<Void, Never>?
35	    
36	    func setDeviceId(deviceId: String) async -> Date? {
37	        self.deviceId = deviceId
38	        self.cached.removeAll()
39	        self.covered = nil
40	        self.liveStart = nil
41	        self.inFlightLeftEdge = nil
42	        self.inFlightTask?.cancel()
43	        self.inFlightTask = nil
44	        
45	        async let date = fetchUseCase.getStartSampleDate(deviceId: deviceId)
46	        return await date
47	    }
48	
49	    func ensure(interval: DateInterval) async {
50	        // Обрезаем правую часть запроса по liveAppendStart, потому что в live-часть в БД не ходим.
51	        guard let dbInterval = clippedDBInterval(for: interval) else { return }
52	
53	        // Вычисляем только недостающий левый кусок.
54	        guard let missingLeft = missingLeftInterval(for: dbInterval) else {
55	            // Если ничего грузить не надо, но подходящий запрос уже in-flight — ждём его.
56	            if let inFlightLeftEdge,
57	               inFlightLeftEdge.intersects(dbInterval),
58	               let inFlightTask {
59	                await inFlightTask.value
60	            }
61	            return
62	         }
63	        
64	        // Уже грузится нужный диапазон, ждём его
65	        if let inFlightLeftEdge,  let inFlightTask,
66	           inFlightLeftEdge.start <= missingLeft.start,
67	           inFlightLeftEdge.end >= missingLeft.end {
68	            await inFlightTask.value
69	            return
70	        }
71	        
72	        // Уже грузится соседний правый кусок — догружаем только левый хвост.
73	        //
74	        // Пример:
75	        // inFlight = [10:00 .. 11:00]
76	        // missing  = [08:00 .. 10:00]
77	        //
78	        // Тогда не повторяем [10:00 .. 11:00], а грузим только [08:00 .. 10:00].
79	        if let inFlightLeftEdge, let inFlightTask,
80	           inFlightLeftEdge.intersects(missingLeft) {
81	            await inFlightTask.value
82	            return await ensure(interval: interval)
83	        }
84	        
85	        await runLoad(for: missingLeft)
86	    }
87	    
88	    func neighbors(for date: Date) async -> (left: DoseCounter?, right: DoseCounter?) {
89	        var left: DoseCounter?
90	        var right: DoseCounter?
91	        
92	        for item in cached {
93	            if item.date <= date {
94	                left = item
95	            }
96	            
97	            if item.date >= date {
98	                right = item
99	                break
100	            }
101	        }
102	        return (left, right)
103	    }
104	    
105	    func countersInside(interval: DateInterval) -> [DoseCounter] {
106	        cached.filter { $0.date > interval.start && $0.date < interval.end }
107	    }
108	    
109	    func appendLive(_ item: DoseCounter) {
110	        let insertIndex = cached.firstIndex {
111	            $0.date == item.date ? $0.id > item.id : $0.date > item.date
112	        } ?? cached.endIndex
113	        
114	        cached.insert(item, at: insertIndex)
115	        
116	        if liveStart == nil {
117	            liveStart = item.date
118	        } else if let liveStart, item.date < liveStart {
119	            self.liveStart = item.date
120	        }
121	    }
122	}
123	
124	private extension DoseCounterCache {
125	        
126	    func clippedDBInterval(for interval: DateInterval) -> DateInterval? {
127	        // В live-часть БД не лезем
128	        if let liveStart, interval.start >= liveStart {
129	            return nil
130	        }
131	        
132	        // Режем правую границу БД интервала по liveAppendStart
133	        let dbEnd = min(interval.end, liveStart ?? interval.end)
134	        
135	        guard dbEnd > interval.start else {
136	            return nil
137	        }
138	        
139	        return DateInterval(start: interval.start, end: dbEnd)
140	    }
141	    
142	    /// Возвращает только недостающий кусок слева от уже покрытого диапазона.
143	    func missingLeftInterval(for dbInterval: DateInterval) -> DateInterval? {
144	        guard let covered else { return dbInterval }
145	        guard covered.start > dbInterval.start else { return nil }
146	        let end = min(dbInterval.end, covered.start)
147	        guard end > dbInterval.start else { return nil }
148	        return DateInterval(start: dbInterval.start, end: end)
149	    }
150	    
151	    // Запускает загрузку из БД для конкретного интервала.
152	    //
153	    // Внутри:
154	    // - сохраняем deviceId, для которого стартовал запрос
155	    // - создаём Task
156	    // - помечаем интервал как in-flight
157	    // - ждём завершения task
158	    //
159	    // Проверка requestedDeviceId потом нужна в finishLoad, чтобы не применить
160	    // результат от старого устройства после переключения deviceId.
161	    func runLoad(for interval: DateInterval) async {
162	        guard interval.duration > 0 else { return }
163	        guard let requestedDeviceId = deviceId else { return }
164	                
165	        let task = Task { [weak self] in
166	            guard let self else { return }
167	            let doseCounter = await fetchUseCase.getDoseSample(deviceId: requestedDeviceId, interval: interval)
168	            await self.finishLoad(interval: interval, requestedDeviceId: requestedDeviceId, items: doseCounter)
169	        }
170	        
171	        inFlightLeftEdge = interval
172	        inFlightTask = task
173	        
174	        await task.value
175	    }
176	    
177	    func finishLoad(interval: DateInterval, requestedDeviceId: String, items: [DoseCounter]) {
178	        defer {
179	            if inFlightLeftEdge == interval {
180	                inFlightLeftEdge = nil
181	                inFlightTask = nil
182	            }
183	        }
184	        guard requestedDeviceId == self.deviceId else { return }
185	        
186	        covered = mergeIntervals(covered, interval)
187	        
188	        guard !items.isEmpty else { return }
189	        
190	        if let firstCached = cached.first, let lastNew = items.last, firstCached.id == lastNew.id {
191	            cached.removeFirst()
192	        }
193	        
194	        cached = items + cached
195	    }
196	    
197	    func mergeIntervals(_ a: DateInterval?, _ b: DateInterval) -> DateInterval {
198	        guard let a else { return b }
199	        return DateInterval(start: min(a.start, b.start), end: max(a.end, b.end))
200	    }
201	}
